// Parse Claude's response
const response = $input.first().json;
const textContent = response.content[0].text;

// Parse the article JSON from Claude's response
let article;
try {
  // Try to extract JSON from the response (handle markdown fences if present)
  const jsonMatch = textContent.match(/\{[\s\S]*\}/);
  article = JSON.parse(jsonMatch[0]);
} catch (e) {
  throw new Error('Failed to parse article JSON from Claude response: ' + e.message);
}

// Add metadata
const today = new Date().toISOString().split('T')[0];
article.date = today;
article.featured = false;
article.status = 'draft';

// Read current articles
const fs = require('fs');
const articlesPath = '/Users/Targo/Downloads/ikigai-mockup/data/articles.json';
const articles = JSON.parse(fs.readFileSync(articlesPath, 'utf-8'));

// Add new article
articles.push(article);

// Save
fs.writeFileSync(articlesPath, JSON.stringify(articles, null, 2), 'utf-8');

return [{
  json: {
    article,
    totalArticles: articles.length,
    previewEs: article.title.es + '\n\n' + article.description.es,
    previewEn: article.title.en + '\n\n' + article.description.en
  }
}];

// Publish the article: change status to published
const fs = require('fs');
const articlesPath = '/Users/Targo/Downloads/ikigai-mockup/data/articles.json';
const articles = JSON.parse(fs.readFileSync(articlesPath, 'utf-8'));

const slug = $('Format & Save Draft').first().json.article.slug;
const article = articles.find(a => a.slug === slug);
if (article) {
  article.status = 'published';
  fs.writeFileSync(articlesPath, JSON.stringify(articles, null, 2), 'utf-8');
}

return [{ json: { slug, status: 'published' } }];

// Reject: remove draft from articles.json
const fs = require('fs');
const articlesPath = '/Users/Targo/Downloads/ikigai-mockup/data/articles.json';
const articles = JSON.parse(fs.readFileSync(articlesPath, 'utf-8'));

const slug = $('Format & Save Draft').first().json.article.slug;
const filtered = articles.filter(a => a.slug !== slug);
fs.writeFileSync(articlesPath, JSON.stringify(filtered, null, 2), 'utf-8');

return [{ json: { slug, status: 'rejected_and_removed' } }];
